/**
 * Devuelve el HTML del icono ya envuelto en <span class="crm-i">.
 *
 * @param string $name  Nombre del icono.
 * @param int    $size  Tamaño en px (default 16).
 * @param string $extra Clases adicionales para el span.
 * @return string
 */
function crm_icon($name, $size = 16, $extra = '') {
    $path = crm_icon_path($name);
    if ($path === '') {
        return '';
    }
    $size  = (int) $size;
    $cls   = trim('crm-i ' . $extra);
    $svg   = sprintf(
        '<svg xmlns="http://www.w3.org/2000/svg" width="%1$d" height="%1$d" viewBox="0 0 256 256" fill="currentColor" aria-hidden="true">%2$s</svg>',
        $size,
        $path
    );
    return sprintf('<span class="%s" aria-hidden="true">%s</span>', esc_attr($cls), $svg);
}

/**
 * Iconos por sector. Devuelve el nombre del icono Phosphor a usar.
 */
function crm_icon_for_sector($sector) {
    $map = [
        'luz'                => 'lightning',
        'gas'                => 'flame',
        'telecomunicaciones' => 'broadcast',
        'alarmas'            => 'shield-check',
        'agua'               => 'drop',
        'asesoria'           => 'scales',
        'asesoría'           => 'scales',
    ];
    $key = strtolower((string) $sector);
    return $map[$key] ?? 'lightning';
}
